def solve(nums: Array[Long], queries: Array[Array[Long]]): Long = {
  val MOD = 1000000007L
  val n = nums.length
  val multiplyCount = Array.ofDim[Int](n)

  for (query <- queries) {
    val li = query(0).toInt
    val ri = query(1).toInt
    val ki = query(2).toInt
    val vi = query(3).toInt
    var idx = li
    while (idx <= ri) {
      multiplyCount(idx) += 1
      idx += ki
    }
  }

  var result = 0L
  for (i <- 0 until n) {
    val power = pow(vi, multiplyCount(i), MOD)
    nums(i) = (nums(i) * power) % MOD
    result ^= nums(i)
  }

  result
}
